      CONJ_TENSES_IT = CONJ_TENSES, CONJ_PRONOUNS_IT = CONJ_PRONOUNS,
      CONJ_PRONOUNS_DE_IT = CONJ_PRONOUNS_DE, BADGES_IT = BADGES;

/* Kurs-Registry: pro Sprache ein Datensatz. Wird unten um es/fr/pt ergänzt. */
const COURSES = {
  it: { corpus: CORPUS_IT, dialoghi: DIALOGHI_IT, conj: CONJ_IT, tenses: CONJ_TENSES_IT, pron: CONJ_PRONOUNS_IT, pronDe: CONJ_PRONOUNS_DE_IT, badges: BADGES_IT },
  en: { corpus: CORPUS_EN, dialoghi: DIALOGHI_EN, conj: CONJ_EN, tenses: CONJ_TENSES_EN, pron: CONJ_PRONOUNS_EN, pronDe: CONJ_PRONOUNS_DE_EN, badges: BADGES_EN }
};
let LANG_ACTIVE = "it";
function selectCourse(lang) {
  const c = COURSES[lang] || COURSES.it;
  LANG_ACTIVE = COURSES[lang] ? lang : "it";
  CORPUS = c.corpus; DIALOGHI = c.dialoghi; CONJUGATIONS = c.conj;
  CONJ_TENSES = c.tenses; CONJ_PRONOUNS = c.pron; CONJ_PRONOUNS_DE = c.pronDe; BADGES = c.badges;
  LESSONS = buildLessons();
  STORY = buildStory(LESSONS);
  return LANG_ACTIVE;
}
